const cw   = $json.current_weather;
const temp = cw.temperature;
const hora = cw.time;
const viento      = cw.windspeed;
const weathercode = cw.weathercode;

const humedad    = $json.hourly?.relative_humidity_2m?.[0] ?? null;
const prob_lluvia = $json.hourly?.precipitation_probability?.[0] ?? null;

const CODIGOS_LLUVIA = [51,53,55,61,63,65,71,73,75,80,81,82,95,96,99];
const esLluvia       = CODIGOS_LLUVIA.includes(weathercode);
const esVientoFuerte = viento > 40;

const descripciones = {
  0: 'cielo despejado', 1: 'mayormente despejado', 2: 'parcialmente nublado',
  3: 'nublado', 45: 'niebla', 51: 'llovizna ligera',
  61: 'lluvia leve', 63: 'lluvia moderada', 65: 'lluvia intensa',
  80: 'chubascos', 95: 'tormenta'
};
const descripcion = descripciones[weathercode] || `codigo ${weathercode}`;

return [{
  json: {
    temperatura: temp,
    viento,
    humedad,
    prob_lluvia,
    weathercode,
    descripcion,
    esLluvia,
    esVientoFuerte,
    hora,
    ciudad: 'Bogota'
  }
}];

const d = $json;
const acciones = ['calefaccion_on', 'cerrar_ventilacion'];
if (d.esVientoFuerte) acciones.push('alerta_viento');
if (d.esLluvia)       acciones.push('cerrar_ventanas');

return [{
  json: {
    ...d,
    estado:    'FRIO',
    prioridad: d.temperatura < 10 ? 'alta' : 'media',
    acciones,
    resumen:   `Frio detectado en ${d.ciudad}: ${d.temperatura}°C, ${d.descripcion}. Humedad: ${d.humedad}%. Viento: ${d.viento} km/h.`,
    timestamp: new Date().toISOString()
  }
}];

const d = $json;
return [{
  json: {
    ...d,
    estado:    'NORMAL',
    prioridad: 'baja',
    acciones:  ['ninguna'],
    resumen:   `Temperatura agradable en ${d.ciudad}: ${d.temperatura}°C, ${d.descripcion}. Todo en orden.`,
    timestamp: new Date().toISOString()
  }
}];

const d = $json;
const acciones = ['ventilacion_maxima', 'bajar_persianas', 'alerta_operadores'];
if (d.esLluvia)       acciones.push('activar_deshumidificador');
if (d.esVientoFuerte) acciones.push('asegurar_estructuras');

return [{
  json: {
    ...d,
    estado:    'CALOR',
    prioridad: d.temperatura > 40 ? 'critica' : 'alta',
    acciones,
    resumen:   `Calor extremo en ${d.ciudad}: ${d.temperatura}°C, ${d.descripcion}. Humedad: ${d.humedad}%. Viento: ${d.viento} km/h.`,
    timestamp: new Date().toISOString()
  }
}];

const d = $json;
const nivel = { critica: 'error', alta: 'warn', media: 'warn', baja: 'log' }[d.prioridad] || 'log';

console[nivel](
  `[${d.estado}] ${d.ciudad} | ${d.temperatura}°C | ${d.descripcion}` +
  ` | Acciones: ${(d.acciones || []).join(', ')}` +
  ` | Prioridad: ${d.prioridad}` +
  ` | ${d.timestamp}`
);

return [{
  json: {
    estado:    d.estado,
    ciudad:    d.ciudad,
    temp:      d.temperatura,
    prioridad: d.prioridad,
    acciones:  d.acciones,
    resumen:   d.resumen,
    timestamp: d.timestamp
  }
}];

const error = $json.error?.message || JSON.stringify($json.error) || 'Error desconocido al consultar la API del clima';
const timestamp = new Date().toISOString();
console.error(`[ERROR CLIMA] ${timestamp} — ${error}`);
return [{
  json: {
    estado:    'ERROR_API',
    error,
    timestamp,
    mensaje:   'No se pudo obtener el clima. Revisando conectividad con Open-Meteo.'
  }
}];
